    pub fn reset(self: *RecvState, alloc: std.mem.Allocator) void {
        if (self.payload) |payload| {
            alloc.free(payload);
        }
        self.payload = null;
        self.payload_read = 0;
        self.header = null;
        self.header_len = 0;
    }
