    payload: ?[]u8 = null,
    payload_read: usize = 0,

    pub fn deinit(self: *RecvState, alloc: std.mem.Allocator) void {
        self.reset(alloc);
    }

    pub fn reset(self: *RecvState, alloc: std.mem.Allocator) void {
        if (self.payload) |payload| {
            alloc.free(payload);
        }
        self.payload = null;
        self.payload_read = 0;
