    uring_loop: if (builtin.os.tag == .linux) ?IoUringEventLoop else void,

    const StartupRelayPhase = enum {
        inactive,
        relay_startup_pending,
        relay_startup_active,
        relay_done,
    };

    const PendingProbeRequest = struct {
        request_id: u32,
        probe_kind: protocol.TerminalProbeKind,
    };

    const StartupRelay = struct {
        phase: StartupRelayPhase = .inactive,
        attached_at_ns: u64 = 0,
        last_probe_activity_ns: u64 = 0,
        next_request_id: u32 = 1,
        pending_requests: std.ArrayListAligned(PendingProbeRequest, null) = .empty,
        inflight_request: ?PendingProbeRequest = null,
        scan_buffer: std.ArrayListAligned(u8, null) = .empty,

        fn deinit(self: *StartupRelay, alloc: std.mem.Allocator) void {
            self.pending_requests.deinit(alloc);
            self.scan_buffer.deinit(alloc);
            self.* = .{};
