        const default_status_right = try alloc.dupe(u8, "#H");
        errdefer alloc.free(default_status_right);

        return .{
            .listen_fd = -1,
            .socket_path = try alloc.dupe(u8, socket_path),
            .sessions = .empty,
            .clients = .empty,
