            .messages = .empty,
            .marked_pane = null,
            .running = false,
            .next_client_id = 1,
            .allocator = alloc,
            .gcd_loop = if (builtin.os.tag == .macos) null else {},
            .uring_loop = if (builtin.os.tag == .linux) null else {},
        };
    }

    pub fn deinit(self: *Server) void {
        self.stop();
