fn handleTerminalProbeReady(self: *Server, client_idx: usize) void {
    if (client_idx >= self.clients.items.len) return;
    const relay = &self.clients.items[client_idx].startup_relay;
    if (relay.phase != .relay_startup_pending) return;
    relay.phase = .relay_startup_active;
    relay.last_probe_activity_ns = monotonicNowNs();
    dispatchNextStartupProbeRequest(self, client_idx);
}

fn handleTerminalProbeResponse(self: *Server, client_idx: usize, payload: []const u8) !void {
    if (client_idx >= self.clients.items.len) return;
    const client = &self.clients.items[client_idx];
    const relay = &client.startup_relay;
    if (relay.phase != .relay_startup_active) return;

    const response = try protocol.decodeTerminalProbeResponse(payload);
    const inflight = relay.inflight_request orelse return;
    if (inflight.request_id != response.request_id) return;

    if (response.status == .complete) {
        const session = client.session orelse return;
        const window = session.active_window orelse return;
        const pane = window.active_pane orelse return;
        self.writePaneInput(pane, response.bytes);
    }

    relay.inflight_request = null;
    relay.last_probe_activity_ns = monotonicNowNs();
    dispatchNextStartupProbeRequest(self, client_idx);
    maybeFinishStartupRelay(self, client_idx);
}

