fn resetStartupRelay(self: *Server, client: *ClientConnection, phase: StartupRelayPhase) void {
    _ = self;
    client.startup_relay.phase = phase;
    client.startup_relay.attached_at_ns = 0;
    client.startup_relay.last_probe_activity_ns = 0;
    client.startup_relay.next_request_id = 1;
    client.startup_relay.pending_requests.clearRetainingCapacity();
    client.startup_relay.scan_buffer.clearRetainingCapacity();
    client.startup_relay.inflight_request = null;
}

