fn dispatchNextStartupProbeRequest(self: *Server, client_idx: usize) void {
    if (client_idx >= self.clients.items.len) return;
    const client = &self.clients.items[client_idx];
    const relay = &client.startup_relay;
    if (relay.phase != .relay_startup_active) return;
    if (relay.inflight_request != null) return;
    if (relay.pending_requests.items.len == 0) {
        maybeFinishStartupRelay(self, client_idx);
        return;
    }

    const request = relay.pending_requests.orderedRemove(0);
    const payload = protocol.encodeTerminalProbeRequest(
        self.allocator,
