    relay.last_probe_activity_ns = monotonicNowNs();
}

fn captureStartupProbeRequests(self: *Server, session: *Session, bytes: []const u8) void {
    const client_idx = findStartupRelayOwnerIndex(self, session) orelse return;
    const relay = &self.clients.items[client_idx].startup_relay;
    switch (relay.phase) {
        .relay_startup_pending, .relay_startup_active => {},
        else => return,
    }

    relay.scan_buffer.appendSlice(self.allocator, bytes) catch return;

    while (detectStartupProbeMatch(relay.scan_buffer.items)) |match| {
        queueStartupProbeRequest(self, client_idx, match.kind);
        relay.last_probe_activity_ns = monotonicNowNs();

        const remove_end = match.index + match.len;
        if (remove_end >= relay.scan_buffer.items.len) {
            relay.scan_buffer.clearRetainingCapacity();
            break;
        }

        const remaining = relay.scan_buffer.items.len - remove_end;
        std.mem.copyForwards(u8, relay.scan_buffer.items[0..remaining], relay.scan_buffer.items[remove_end..]);
        relay.scan_buffer.shrinkRetainingCapacity(remaining);
    }

    const keep = startupProbeSuffixLen(relay.scan_buffer.items);
    if (keep == 0) {
        relay.scan_buffer.clearRetainingCapacity();
    } else if (keep < relay.scan_buffer.items.len) {
        const start = relay.scan_buffer.items.len - keep;
        std.mem.copyForwards(u8, relay.scan_buffer.items[0..keep], relay.scan_buffer.items[start..]);
        relay.scan_buffer.shrinkRetainingCapacity(keep);
    }

    dispatchNextStartupProbeRequest(self, client_idx);
}

